// For each symbol, build Kite historical data URL (90 days)
const symbols = $input.all().map(i => i.json.symbol);
const now = new Date();
const from = new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);
const fromStr = from.toISOString().split('T')[0];
const toStr = now.toISOString().split('T')[0];

// Return list for Split In Batches node
return symbols.map(s => ({
  json: {
    symbol: s,
    url: `https://api.kite.trade/instruments/historical/NSE:${s}/day?from=${fromStr}+09:15:00&to=${toStr}+15:30:00`
  }
}));

// FULL TECHNICAL ANALYSIS ENGINE
// Calculates: SMA, EMA, RSI, MACD, Bollinger, ATR, Support/Resistance, Volume Analysis, Momentum Score

const symbol = $('Process Each Symbol').item.json.symbol;
const kiteResponse = $input.first().json;
const candles = kiteResponse.data?.candles || [];

if (candles.length < 30) {
  return [{ json: { symbol, error: 'Insufficient data', candle_count: candles.length } }];
}

// Parse candle data: [date, open, high, low, close, volume]
const dates = candles.map(c => c[0]);
const opens = candles.map(c => c[1]);
const highs = candles.map(c => c[2]);
const lows = candles.map(c => c[3]);
const closes = candles.map(c => c[4]);
const volumes = candles.map(c => c[5]);

// ===== MOVING AVERAGES =====
function sma(data, period) {
  if (data.length < period) return null;
  return data.slice(-period).reduce((a, b) => a + b, 0) / period;
}

function ema(data, period) {
  if (data.length < period) return null;
  const k = 2 / (period + 1);
  let ema = data.slice(0, period).reduce((a, b) => a + b, 0) / period;
  for (let i = period; i < data.length; i++) {
    ema = data[i] * k + ema * (1 - k);
  }
  return ema;
}

const sma5 = sma(closes, 5);
const sma10 = sma(closes, 10);
const sma20 = sma(closes, 20);
const sma50 = sma(closes, 50);
const sma200 = closes.length >= 200 ? sma(closes, 200) : null;
const ema9 = ema(closes, 9);
const ema12 = ema(closes, 12);
const ema21 = ema(closes, 21);
const ema26 = ema(closes, 26);

// ===== RSI (Wilder's Smoothing) =====
function calcRSI(data, period = 14) {
  if (data.length < period + 1) return null;
  let gains = 0, losses = 0;
  for (let i = 1; i <= period; i++) {
    const diff = data[i] - data[i-1];
    if (diff > 0) gains += diff; else losses += Math.abs(diff);
  }
  let avgGain = gains / period;
  let avgLoss = losses / period;
  for (let i = period + 1; i < data.length; i++) {
    const diff = data[i] - data[i-1];
    avgGain = (avgGain * (period - 1) + Math.max(diff, 0)) / period;
    avgLoss = (avgLoss * (period - 1) + Math.max(-diff, 0)) / period;
  }
  if (avgLoss === 0) return 100;
  return 100 - (100 / (1 + avgGain / avgLoss));
}
const rsi14 = calcRSI(closes);

// ===== MACD =====
const macdLine = ema12 && ema26 ? ema12 - ema26 : null;
// Signal line approximation
const macdValues = [];
if (closes.length >= 26) {
  const k12 = 2/13, k26 = 2/27;
  let e12 = closes.slice(0,12).reduce((a,b)=>a+b,0)/12;
  let e26 = closes.slice(0,26).reduce((a,b)=>a+b,0)/26;
  for (let i = 26; i < closes.length; i++) {
    e12 = closes[i]*k12 + e12*(1-k12);
    e26 = closes[i]*k26 + e26*(1-k26);
    macdValues.push(e12 - e26);
  }
}
const signalLine = macdValues.length >= 9 ? ema(macdValues, 9) : null;
const macdHistogram = macdLine && signalLine ? macdLine - signalLine : null;

// ===== BOLLINGER BANDS =====
function calcBollinger(data, period = 20, mult = 2) {
  if (data.length < period) return null;
  const slice = data.slice(-period);
  const mean = slice.reduce((a, b) => a + b, 0) / period;
  const stdDev = Math.sqrt(slice.reduce((s, v) => s + Math.pow(v - mean, 2), 0) / period);
  const price = data[data.length - 1];
  return {
    upper: mean + mult * stdDev,
    middle: mean,
    lower: mean - mult * stdDev,
    bandwidth: stdDev > 0 ? (4 * mult * stdDev / mean * 100) : 0,
    percentB: stdDev > 0 ? (price - (mean - mult * stdDev)) / (2 * mult * stdDev) : 0.5
  };
}
const bb = calcBollinger(closes);

// ===== ATR (14-period) =====
function calcATR(highs, lows, closes, period = 14) {
  if (highs.length < period + 1) return null;
  const trs = [];
  for (let i = 1; i < highs.length; i++) {
    trs.push(Math.max(
      highs[i] - lows[i],
      Math.abs(highs[i] - closes[i-1]),
      Math.abs(lows[i] - closes[i-1])
    ));
  }
  let atr = trs.slice(0, period).reduce((a,b) => a+b, 0) / period;
  for (let i = period; i < trs.length; i++) {
    atr = (atr * (period - 1) + trs[i]) / period;
  }
  return atr;
}
const atr14 = calcATR(highs, lows, closes);

// ===== SUPPORT & RESISTANCE =====
const lastClose = closes[closes.length - 1];
const lastHigh = highs[highs.length - 1];
const lastLow = lows[lows.length - 1];
const pivot = (lastHigh + lastLow + lastClose) / 3;
const r1 = 2 * pivot - lastLow;
const s1 = 2 * pivot - lastHigh;
const r2 = pivot + (lastHigh - lastLow);
const s2 = pivot - (lastHigh - lastLow);
const high20 = Math.max(...highs.slice(-20));
const low20 = Math.min(...lows.slice(-20));

// ===== VOLUME ANALYSIS =====
const currentVol = volumes[volumes.length - 1];
const avgVol5 = sma(volumes, 5);
const avgVol20 = sma(volumes, 20);
const volRatio = avgVol20 ? currentVol / avgVol20 : 1;

// OBV trend (last 10 days)
let obv = 0;
const obvValues = [0];
for (let i = 1; i < closes.length; i++) {
  if (closes[i] > closes[i-1]) obv += volumes[i];
  else if (closes[i] < closes[i-1]) obv -= volumes[i];
  obvValues.push(obv);
}
const obvTrend = obvValues.length >= 10 
  ? (obvValues[obvValues.length-1] > obvValues[obvValues.length-10] ? 'rising' : 'falling')
  : 'neutral';

// ===== TREND CLASSIFICATION =====
let trend = 'SIDEWAYS';
if (lastClose > (sma50 || 0) && lastClose > (sma20 || 0) && (sma20 || 0) > (sma50 || 0)) {
  trend = rsi14 > 60 ? 'STRONG_BULLISH' : 'BULLISH';
} else if (lastClose < (sma50 || Infinity) && lastClose < (sma20 || Infinity)) {
  trend = rsi14 < 40 ? 'STRONG_BEARISH' : 'BEARISH';
}

// ===== MOMENTUM SCORE (0-100) =====
let momentum = 50;
if (rsi14) momentum += (rsi14 - 50) * 0.3;
if (macdHistogram) momentum += (macdHistogram > 0 ? 10 : -10);
if (lastClose > (sma20 || 0)) momentum += 5;
if (lastClose > (sma50 || 0)) momentum += 5;
if (obvTrend === 'rising') momentum += 5;
else if (obvTrend === 'falling') momentum -= 5;
momentum = Math.max(0, Math.min(100, momentum));

// ===== AVERAGE DAILY MOVE =====
const dailyMoves = [];
for (let i = Math.max(1, closes.length - 20); i < closes.length; i++) {
  dailyMoves.push(Math.abs(closes[i] - closes[i-1]) / closes[i-1] * 100);
}
const avgDailyMove = dailyMoves.length > 0 
  ? dailyMoves.reduce((a,b) => a+b, 0) / dailyMoves.length : 0;

return [{
  json: {
    symbol: symbol,
    last_close: lastClose,
    candle_count: candles.length,
    moving_averages: {
      sma5, sma10, sma20, sma50, sma200,
      ema9, ema12, ema21, ema26
    },
    rsi: rsi14,
    macd: { line: macdLine, signal: signalLine, histogram: macdHistogram },
    bollinger: bb,
    atr: atr14,
    support_resistance: { pivot, r1, r2, s1, s2, high20, low20 },
    volume: {
      current: currentVol,
      avg_5d: avgVol5,
      avg_20d: avgVol20,
      ratio: volRatio,
      obv_trend: obvTrend
    },
    trend: trend,
    momentum_score: Math.round(momentum),
    avg_daily_move_pct: avgDailyMove.toFixed(2),
    calculated_at: new Date().toISOString()
  }
}];
